SELECT b.id, b.site_id, b.batch_code, b.batch_name, b.import_date, b.import_source, b.title_count, b.category_id, b.status, b.remark, b.create_by, b.create_time, b.update_by, b.update_time, COALESCE(s.name, CAST(b.site_id AS CHAR)) as site_name, c.name as category_name, c.icon as category_icon, -- 统一的可见性状态： -- 1. 网站自己的批次：使用批次本身的status -- 2. 用户默认站点配置： -- - 如果有关联记录（incl.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站批次：使用关联表的is_visible（必须有关联记录才能访问） CASE WHEN b.site_id = #{siteId} THEN b.status WHEN b.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE IFNULL(incl.is_visible, '0') END as is_visible, -- 关联来源标识：own(自己的) | default(默认配置) | shared(其他网站分享) CASE WHEN b.site_id = #{siteId} THEN 'own' WHEN b.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN b.site_id = #{params.personalSiteId} AND incl.id IS NULL AND excl.id IS NOT NULL THEN '1' ELSE '0' END as is_excluded, -- 关联的网站数量 (SELECT COUNT(*) FROM gb_site_title_batch_relations r WHERE r.title_batch_id = b.id AND r.relation_type = 'include') as related_sites_count, -- 排除的网站数量 (SELECT COUNT(*) FROM gb_site_title_batch_relations r WHERE r.title_batch_id = b.id AND r.relation_type = 'exclude') as excluded_sites_count FROM gb_title_pool_batch b LEFT JOIN gb_sites s ON b.site_id = s.id LEFT JOIN gb_categories c ON b.category_id = c.id -- 左连接正向关联（include） LEFT JOIN gb_site_title_batch_relations incl ON b.id = incl.title_batch_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_title_batch_relations excl ON b.id = excl.title_batch_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude'
AND ( b.site_id = #{siteId}
OR b.site_id = #{params.personalSiteId}
OR (b.site_id != #{siteId}
AND b.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) ) AND b.batch_code = #{batchCode} AND b.batch_name LIKE CONCAT('%', #{batchName}, '%')
AND b.import_date BETWEEN #{params.beginImportDate} AND #{params.endImportDate}
AND b.import_source = #{importSource} AND b.category_id = #{categoryId} AND b.status = #{status}
ORDER BY b.site_id, b.import_date DESC, b.id DESC

