mapper.update:
UPDATE gb_title_pool_batch
site_id = #{siteId}, batch_code = #{batchCode}, batch_name = #{batchName}, import_date = #{importDate}, import_source = #{importSource}, title_count = #{titleCount}, category_id = #{categoryId}, status = #{status}, remark = #{remark}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime},
WHERE id = #{id}

UPDATE gb_title_pool 
SET del_flag = '2'
WHERE import_batch = (
    SELECT batch_code COLLATE utf8mb4_unicode_ci 
    FROM gb_title_pool_batch WHERE id = #{id}
)

UPDATE gb_title_pool SET del_flag = '2' WHERE import_batch IN ( SELECT batch_code COLLATE utf8mb4_unicode_ci FROM gb_title_pool_batch WHERE id IN
#{id}
)

UPDATE gb_title_pool_batch b
SET b.title_count = (
    SELECT COUNT(*)
    FROM gb_title_pool t
    WHERE t.import_batch = #{batchCode}
      AND t.del_flag = '0'
)
WHERE b.batch_code = #{batchCode}

